    public List<ExamenFisicoDTO> listExamenFisicoIdUsuarioUltimo(Long idUsuario) {
        this.sql = "SELECT  IF(`h_examenfisico`.`Peso`=0,NULL,`h_examenfisico`.`Peso`) AS Peso  , if(`h_examenfisico`.`Talla`=0, NULL,`h_examenfisico`.`Talla`) AS Talla  , if(`h_examenfisico`.`PerimetroAbdominal`=0, NULL,`h_examenfisico`.`PerimetroAbdominal`) AS PAbdominal  FROM  `h_atencion` INNER JOIN  `h_examenfisico`   ON (`h_atencion`.`Id` = `h_examenfisico`.`Id_Atencion`) INNER JOIN `ingreso`  ON (`h_atencion`.`Id_Ingreso` = `ingreso`.`Id`) WHERE (`ingreso`.`Id_Usuario` =" + idUsuario + " AND `h_examenfisico`.`Peso` <>0) ORDER BY `ingreso`.`FechaIngreso` DESC LIMIT 1  ";
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.historia.HistoriaDAOImpl.1
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                ExamenFisicoDTO g = new ExamenFisicoDTO();
                g.setPeso(Double.valueOf(rs.getDouble("Peso")));
                g.setTalla(Double.valueOf(rs.getDouble("Talla")));
                g.setPAbdominal(Double.valueOf(rs.getDouble("PAbdominal")));
                return g;
            }
        };
        List<ExamenFisicoDTO> list = this.jdbcTemplate.query(this.sql, mapper);
        return list;
    }

