    @Override // com.genoma.plus.dao.historia.HistoriaDAO
    public List<Object[]> listadoMedicamentosOrdenFiltradoNombre(String nombre) {
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.historia.HistoriaDAOImpl.5
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                Object[] fila = {Long.valueOf(rs.getLong("IdSuministro")), rs.getString("NSuministro"), rs.getString("NConcentracion"), Double.valueOf(rs.getDouble("NInvima")), Double.valueOf(rs.getDouble("valorNumerico")), Boolean.valueOf(rs.getBoolean("EsAmpolla")), Boolean.valueOf(rs.getBoolean("VFinvima")), Boolean.valueOf(rs.getBoolean("CInventario")), false, Long.valueOf(rs.getLong("IdPrincipioActivo"))};
                return fila;
            }
        };
        this.sql = "SELECT i_suministro.Id AS IdSuministro, UPPER(CONCAT(IF(i_principioactivo.`Nbre`='NO APLICA',i_suministro.`Nbre`,i_principioactivo.`Nbre`),' ', IF(i_concentracion.`Nbre`='NO APLICA' OR i_concentracion.`Nbre`='-','',i_concentracion.`Nbre`) ,' ', IF(i_presentacionfarmaceutica.`Nbre`='NO APLICA','', i_presentacionfarmaceutica.`Nbre`))) AS NSuministro,\n concat(i_concentracion.Nbre, ' ',  i_presentacioncomercial.`Nbre`)  AS NConcentracion ,CONVERT(i_concentracion.`NInvima` , DOUBLE) NInvima \n , i_presentacioncomercial.`valorNumerico`\n  , i_presentacionfarmaceutica.EsAmpolla, IF((i_suministro.FechaVInvima<=NOW()),0,1) AS VFinvima,\n  i_suministroxbodega.CInventario, `i_suministro`.`IdPrincipioActivo`  \n FROM  `i_suministro` INNER JOIN `i_principioactivo`  ON (`i_suministro`.`IdPrincipioActivo` = `i_principioactivo`.`Id`) \nINNER JOIN `i_presentacioncomercial`  ON (`i_suministro`.`IdPresentacionComercial` = `i_presentacioncomercial`.`Id`)\n INNER JOIN `i_presentacionfarmaceutica`  ON (`i_suministro`.`IdPresentacionFarmaceutica` = `i_presentacionfarmaceutica`.`Id`) \nINNER JOIN `i_laboratorio`   ON (`i_suministro`.`IdLaboratorio` = `i_laboratorio`.`Id`) \nINNER JOIN `i_concentracion`  ON (`i_suministro`.`IdConcentracion` = `i_concentracion`.`Id`) \nINNER JOIN `i_suministroxbodega`  ON (`i_suministroxbodega`.`IdSuministro` = `i_suministro`.`Id`) \nINNER JOIN `i_suministroxlotexbodega`  ON (`i_suministroxlotexbodega`.`Id` = `i_suministroxbodega`.`Id`) \nINNER JOIN `i_bodegas`  ON (`i_suministroxbodega`.`IdBodega` = `i_bodegas`.`Id`) \n\nWHERE (i_bodegas.EsUrg=1    AND `i_suministro`.ActivoHc=1  AND i_principioactivo.Nbre<>'-' \nAND (UPPER(CONCAT(IF(i_principioactivo.`Nbre`='NO APLICA',i_suministro.`Nbre`,i_principioactivo.`Nbre`),' ', IF(i_concentracion.`Nbre`='NO APLICA' OR i_concentracion.`Nbre`='-','',i_concentracion.`Nbre`) ,' ', IF(i_presentacionfarmaceutica.`Nbre`='NO APLICA','', i_presentacionfarmaceutica.`Nbre`))) LIKE '%" + nombre + "%' OR i_suministro.Id = '" + nombre + "'))  \nGROUP BY IdSuministro ORDER BY i_principioactivo.Nbre, i_presentacionfarmaceutica.Nbre, i_suministroxbodega.Costo, IdSuministro, i_suministro.Nbre  ";
        List<Object[]> list = this.jdbcTemplate.query(this.sql, mapper);
        return list;
    }

