    public List<Object[]> listadoHistoricoOrdenesMedicamentosNuevo(Long idIngreso, String fecha, Boolean filtro) {
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.historia.HistoriaDAOImpl.6
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                Object[] fila = {Long.valueOf(rs.getLong("idOrdenUnidosis")), rs.getString("FechaOrden"), Long.valueOf(rs.getLong("idSuministro")), rs.getString("nombreSumimistro"), Boolean.valueOf(rs.getBoolean("trasladar")), Boolean.valueOf(rs.getBoolean("Infusion")), rs.getString("dosis"), rs.getString("via"), rs.getString("frecuencia"), Double.valueOf(rs.getDouble("duracion")), Double.valueOf(rs.getDouble("cantidad")), rs.getString("especialdiad"), rs.getString("profesional"), rs.getString("Observacion"), Long.valueOf(rs.getLong("idSuministroDilucion")), rs.getString("nombreSuministroDiliyente"), Double.valueOf(rs.getDouble("velocidad")), Double.valueOf(rs.getDouble("volumen")), rs.getString("forma"), rs.getString("fechaSuspencion"), rs.getString("observacionSuspencion"), Boolean.valueOf(rs.getBoolean("Aplicado")), Boolean.valueOf(rs.getBoolean("Cerrada")), Long.valueOf(rs.getLong("idDetalleUnidosis")), Long.valueOf(rs.getLong("DosisN")), Long.valueOf(rs.getLong("FrecuenciaN")), rs.getString("tipoFecuencia")};
                return fila;
            }
        };
        if (filtro.booleanValue()) {
            this.sql = "SELECT\n    `h_ordenes_unidosis`.`Id` AS `idOrdenUnidosis`\n    , `h_ordenes_unidosis`.`Fecha` AS `FechaOrden`\n    , `i_suministro`.`Id` AS `idSuministro`\n    , UPPER(CONCAT(IF(i_principioactivo.`Nbre`='NO APLICA',i_suministro.`Nbre`,i_principioactivo.`Nbre`),' ', IF(i_concentracion.`Nbre`='NO APLICA' OR i_concentracion.`Nbre`='-','',i_concentracion.`Nbre`) ,' ', IF(i_presentacioncomercial.`Nbre`='NO APLICA','', i_presentacioncomercial.`Nbre`))) AS `nombreSumimistro`\n    , false as trasladar, `h_ordenes_unidosis_detalle`.`Infusion`\n    , IF(`h_ordenes_unidosis_detalle`.`DosisN`=0, `h_ordenes_unidosis_detalle`.`Dosis`, CONCAT(`h_ordenes_unidosis_detalle`.`DosisN`, ' ', i_unidadmedida.`Nbre`)) AS `dosis`\n    , `h_ordenes_unidosis_detalle`.`via`\n    , IF(`h_ordenes_unidosis_detalle`.`FrecuenciaN`=0, `h_ordenes_unidosis_detalle`.`Frecuencia`, CONCAT(`h_ordenes_unidosis_detalle`.`FrecuenciaN`, ' ', `h_ordenes_unidosis_detalle`.`tipoFecuencia`)) AS `frecuencia`\n    , IF(`h_ordenes_unidosis_detalle`.`DuracionD`=0, 0, `h_ordenes_unidosis_detalle`.`DuracionD`)  AS `duracion`\n    , `h_ordenes_unidosis_detalle`.`Cantidad` AS `cantidad`\n    , `h_ordenes_unidosis_detalle`.`Observacion`\n    , IFNULL(`h_ordenes_unidosis_detalle_dilucion`.`idSuministro`, 0) idSuministroDilucion\n    , IFNULL(UPPER(CONCAT(IF(i_principioactivo1.`Nbre`='NO APLICA',i_suministro_1.`Nbre`,i_principioactivo1.`Nbre`),' ', IF(i_concentracion1.`Nbre`='NO APLICA' OR i_concentracion1.`Nbre`='-','',i_concentracion1.`Nbre`) ,' ', IF(i_presentacioncomercial1.`Nbre`='NO APLICA','', i_presentacioncomercial1.`Nbre`))),'') nombreSuministroDiliyente\n    , IFNULL(h_ordenes_unidosis_detalle_dilucion.`velocidad`, 0) velocidad\n    , IFNULL(h_ordenes_unidosis_detalle_dilucion.`volumen`, 0) volumen\n    , IFNULL(h_ordenes_unidosis_detalle_dilucion.`forma`, '') forma\n    , IFNULL(h_ordenes_unidosis_detalle_suspension.`fechaSuspension`,'') fechaSuspencion\n    , IFNULL(h_ordenes_unidosis_detalle_suspension.`observacion`, '') observacionSuspencion\n    , h_ordenes_unidosis_detalle.`Aplicado`\n    , h_ordenes_unidosis_detalle.`Cerrada`, g_especialidad.`Nbre` especialdiad\n    , CONCAT(profesional.`Apellido1`,' ', profesional.`Apellido2`,' ', profesional.`Nombre1`,' ', profesional.`Nombre2`) profesional, `h_ordenes_unidosis_detalle`.`Id` idDetalleUnidosis\n     , `h_ordenes_unidosis_detalle`.`DosisN`, `h_ordenes_unidosis_detalle`.`FrecuenciaN`, `h_ordenes_unidosis_detalle`.`tipoFecuencia` \n FROM\n    `h_ordenes_unidosis_detalle`\n    INNER JOIN `h_ordenes_unidosis` \n        ON (`h_ordenes_unidosis_detalle`.`Id_Ordenes` = `h_ordenes_unidosis`.`Id`)\n    INNER JOIN `g_tipoatencion` \n        ON (`h_ordenes_unidosis`.`Tipo` = `g_tipoatencion`.`Id`)\n    INNER JOIN `i_suministro` \n        ON (`h_ordenes_unidosis_detalle`.`Id_Suministro` = `i_suministro`.`Id`)\n    INNER JOIN `i_principioactivo` \n        ON (`i_suministro`.`IdPrincipioActivo` = `i_principioactivo`.`Id`)\n    INNER JOIN `i_concentracion` \n        ON (`i_suministro`.`IdConcentracion` = `i_concentracion`.`Id`)\n    INNER JOIN `i_presentacionfarmaceutica` \n        ON (`i_suministro`.`IdPresentacionFarmaceutica` = `i_presentacionfarmaceutica`.`Id`)\n    INNER JOIN `i_presentacioncomercial` \n        ON (`i_suministro`.`IdPresentacionComercial` = `i_presentacioncomercial`.`Id`)\n    INNER JOIN `i_unidadmedida` \n        ON (`i_suministro`.`IdUnidadMedida` = `i_unidadmedida`.`Id`)\n    INNER JOIN `i_tipoproducto` \n        ON (`i_suministro`.`IdTipoProducto` = `i_tipoproducto`.`Id`)\n    INNER JOIN `g_especialidad` \n        ON (`h_ordenes_unidosis`.`Id_Especialidad` = `g_especialidad`.`Id`)\n    INNER JOIN `g_persona` AS `profesional` \n        ON (`profesional`.`Id` = `h_ordenes_unidosis`.`Id_Profesional`)\n    LEFT JOIN `h_ordenes_unidosis_detalle_dilucion` \n        ON (`h_ordenes_unidosis_detalle_dilucion`.`idOrdenesUnidosis` = `h_ordenes_unidosis_detalle`.`Id`) AND (h_ordenes_unidosis_detalle_dilucion.`Estado`=1)\n    LEFT JOIN `i_suministro` AS `i_suministro_1` \n        ON (`i_suministro_1`.`Id` = `h_ordenes_unidosis_detalle_dilucion`.`idSuministro`)\n    LEFT JOIN `i_principioactivo` i_principioactivo1\n        ON (`i_suministro_1`.`IdPrincipioActivo` = `i_principioactivo1`.`Id`)\n    LEFT JOIN `i_concentracion` i_concentracion1\n        ON (`i_suministro_1`.`IdConcentracion` = `i_concentracion1`.`Id`)\n    LEFT JOIN `i_presentacionfarmaceutica` i_presentacionfarmaceutica1\n        ON (`i_suministro_1`.`IdPresentacionFarmaceutica` = `i_presentacionfarmaceutica1`.`Id`)\n    LEFT JOIN `i_presentacioncomercial` i_presentacioncomercial1\n        ON (`i_suministro_1`.`IdPresentacionComercial` = `i_presentacioncomercial1`.`Id`)\n    LEFT JOIN `i_unidadmedida` i_unidadmedida1\n        ON (`i_suministro_1`.`IdUnidadMedida` = `i_unidadmedida1`.`Id`)\n    LEFT JOIN `i_tipoproducto` i_tipoproducto1\n        ON (`i_suministro_1`.`IdTipoProducto` = `i_tipoproducto1`.`Id`)    \n    LEFT JOIN `h_ordenes_unidosis_detalle_suspension`\n        ON(`h_ordenes_unidosis_detalle_suspension`.`idDetalleUnidosis`=h_ordenes_unidosis_detalle.`Id`) AND (h_ordenes_unidosis_detalle_suspension.`estado`=1)   \nWHERE (`h_ordenes_unidosis`.`Id_Ingreso` =" + idIngreso + " AND h_ordenes_unidosis.`Estado`=1\n    AND `i_tipoproducto`.`Tipo` =1)\nORDER BY `FechaOrden` DESC, `idOrdenUnidosis` ASC, `nombreSumimistro` ASC";
        } else {
            this.sql = "SELECT\n    `h_ordenes_unidosis`.`Id` AS `idOrdenUnidosis`\n    , `h_ordenes_unidosis`.`Fecha` AS `FechaOrden`\n    , `i_suministro`.`Id` AS `idSuministro`\n    , UPPER(CONCAT(IF(i_principioactivo.`Nbre`='NO APLICA',i_suministro.`Nbre`,i_principioactivo.`Nbre`),' ', IF(i_concentracion.`Nbre`='NO APLICA' OR i_concentracion.`Nbre`='-','',i_concentracion.`Nbre`) ,' ', IF(i_presentacioncomercial.`Nbre`='NO APLICA','', i_presentacioncomercial.`Nbre`))) AS `nombreSumimistro`\n    , false as trasladar, `h_ordenes_unidosis_detalle`.`Infusion`\n    , IF(`h_ordenes_unidosis_detalle`.`DosisN`=0, `h_ordenes_unidosis_detalle`.`Dosis`, CONCAT(`h_ordenes_unidosis_detalle`.`DosisN`, ' ', i_unidadmedida.`Nbre`)) AS `dosis`\n    , `h_ordenes_unidosis_detalle`.`via`\n    , IF(`h_ordenes_unidosis_detalle`.`FrecuenciaN`=0, `h_ordenes_unidosis_detalle`.`Frecuencia`, CONCAT(`h_ordenes_unidosis_detalle`.`FrecuenciaN`, ' ', `h_ordenes_unidosis_detalle`.`tipoFecuencia`)) AS `frecuencia`\n    , IF(`h_ordenes_unidosis_detalle`.`DuracionD`=0, 0, `h_ordenes_unidosis_detalle`.`DuracionD`)  AS `duracion`\n    , `h_ordenes_unidosis_detalle`.`Cantidad` AS `cantidad`\n    , `h_ordenes_unidosis_detalle`.`Observacion`\n    , IFNULL(`h_ordenes_unidosis_detalle_dilucion`.`idSuministro`, 0) idSuministroDilucion\n    , IFNULL(UPPER(CONCAT(IF(i_principioactivo1.`Nbre`='NO APLICA',i_suministro_1.`Nbre`,i_principioactivo1.`Nbre`),' ', IF(i_concentracion1.`Nbre`='NO APLICA' OR i_concentracion1.`Nbre`='-','',i_concentracion1.`Nbre`) ,' ', IF(i_presentacioncomercial1.`Nbre`='NO APLICA','', i_presentacioncomercial1.`Nbre`))),'') nombreSuministroDiliyente\n    , IFNULL(h_ordenes_unidosis_detalle_dilucion.`velocidad`, 0) velocidad\n    , IFNULL(h_ordenes_unidosis_detalle_dilucion.`volumen`, 0) volumen\n    , IFNULL(h_ordenes_unidosis_detalle_dilucion.`forma`, '') forma\n    , IFNULL(h_ordenes_unidosis_detalle_suspension.`fechaSuspension`,'') fechaSuspencion\n    , IFNULL(h_ordenes_unidosis_detalle_suspension.`observacion`, '') observacionSuspencion\n    , h_ordenes_unidosis_detalle.`Aplicado`\n    , h_ordenes_unidosis_detalle.`Cerrada`, g_especialidad.`Nbre` especialdiad\n    , CONCAT(profesional.`Apellido1`,' ', profesional.`Apellido2`,' ', profesional.`Nombre1`,' ', profesional.`Nombre2`) profesional, `h_ordenes_unidosis_detalle`.`Id` idDetalleUnidosis\n     , `h_ordenes_unidosis_detalle`.`DosisN`, `h_ordenes_unidosis_detalle`.`FrecuenciaN`, `h_ordenes_unidosis_detalle`.`tipoFecuencia` \n FROM\n    `h_ordenes_unidosis_detalle`\n    INNER JOIN `h_ordenes_unidosis` \n        ON (`h_ordenes_unidosis_detalle`.`Id_Ordenes` = `h_ordenes_unidosis`.`Id`)\n    INNER JOIN `g_tipoatencion` \n        ON (`h_ordenes_unidosis`.`Tipo` = `g_tipoatencion`.`Id`)\n    INNER JOIN `i_suministro` \n        ON (`h_ordenes_unidosis_detalle`.`Id_Suministro` = `i_suministro`.`Id`)\n    INNER JOIN `i_principioactivo` \n        ON (`i_suministro`.`IdPrincipioActivo` = `i_principioactivo`.`Id`)\n    INNER JOIN `i_concentracion` \n        ON (`i_suministro`.`IdConcentracion` = `i_concentracion`.`Id`)\n    INNER JOIN `i_presentacionfarmaceutica` \n        ON (`i_suministro`.`IdPresentacionFarmaceutica` = `i_presentacionfarmaceutica`.`Id`)\n    INNER JOIN `i_presentacioncomercial` \n        ON (`i_suministro`.`IdPresentacionComercial` = `i_presentacioncomercial`.`Id`)\n    INNER JOIN `i_unidadmedida` \n        ON (`i_suministro`.`IdUnidadMedida` = `i_unidadmedida`.`Id`)\n    INNER JOIN `i_tipoproducto` \n        ON (`i_suministro`.`IdTipoProducto` = `i_tipoproducto`.`Id`)\n    INNER JOIN `g_especialidad` \n        ON (`h_ordenes_unidosis`.`Id_Especialidad` = `g_especialidad`.`Id`)\n    INNER JOIN `g_persona` AS `profesional` \n        ON (`profesional`.`Id` = `h_ordenes_unidosis`.`Id_Profesional`)\n    LEFT JOIN `h_ordenes_unidosis_detalle_dilucion` \n        ON (`h_ordenes_unidosis_detalle_dilucion`.`idOrdenesUnidosis` = `h_ordenes_unidosis_detalle`.`Id`) AND (h_ordenes_unidosis_detalle_dilucion.`Estado`=1)\n    LEFT JOIN `i_suministro` AS `i_suministro_1` \n        ON (`i_suministro_1`.`Id` = `h_ordenes_unidosis_detalle_dilucion`.`idSuministro`)\n    LEFT JOIN `i_principioactivo` i_principioactivo1\n        ON (`i_suministro_1`.`IdPrincipioActivo` = `i_principioactivo1`.`Id`)\n    LEFT JOIN `i_concentracion` i_concentracion1\n        ON (`i_suministro_1`.`IdConcentracion` = `i_concentracion1`.`Id`)\n    LEFT JOIN `i_presentacionfarmaceutica` i_presentacionfarmaceutica1\n        ON (`i_suministro_1`.`IdPresentacionFarmaceutica` = `i_presentacionfarmaceutica1`.`Id`)\n    LEFT JOIN `i_presentacioncomercial` i_presentacioncomercial1\n        ON (`i_suministro_1`.`IdPresentacionComercial` = `i_presentacioncomercial1`.`Id`)\n    LEFT JOIN `i_unidadmedida` i_unidadmedida1\n        ON (`i_suministro_1`.`IdUnidadMedida` = `i_unidadmedida1`.`Id`)\n    LEFT JOIN `i_tipoproducto` i_tipoproducto1\n        ON (`i_suministro_1`.`IdTipoProducto` = `i_tipoproducto1`.`Id`)    \n    LEFT JOIN `h_ordenes_unidosis_detalle_suspension`\n        ON(`h_ordenes_unidosis_detalle_suspension`.`idDetalleUnidosis`=h_ordenes_unidosis_detalle.`Id`) AND (h_ordenes_unidosis_detalle_suspension.`estado`=1)   \nWHERE (`h_ordenes_unidosis`.`Id_Ingreso` =" + idIngreso + " AND  date_format(`h_ordenes_unidosis`.`Fecha`, '%Y-%m-%d')='" + fecha + "' and  h_ordenes_unidosis.`Estado`=1\n    AND `i_tipoproducto`.`Tipo` =1)\nORDER BY `FechaOrden` DESC, `idOrdenUnidosis` ASC, `nombreSumimistro` ASC";
        }
        List<Object[]> list = this.jdbcTemplate.query(this.sql, mapper);
        return list;
    }

